101 +
102 +        return hasPermission(group.getId(), AdminPermissionsSchema.MANAGE, AdminPermissionsSchema.MANAGE_MEMBERSHIP);
103 +    }
104 +
105 +    @Override
106 +    public Set<String> getGroupIdsWithViewPermission() {
107 +        if (root.users().canView()) return Collections.emptySet();
108 +
109 +        if (!root.isAdminSameRealm()) {
110 +            return Collections.emptySet();
111 +        }
112 +
113 +        ResourceServer server = root.realmResourceServer();
114 +
115 +        if (server == null) {
116 +            return Collections.emptySet();
117 +        }
118 +
119 +        Set<String> granted = new HashSet<>();
120 +
121 +        resourceStore.findByType(server, AdminPermissionsSchema.GROUPS_RESOURCE_TYPE, groupResource -> {
122 +            if (hasPermission(groupResource.getId(), AdminPermissionsSchema.VIEW_MEMBERS, AdminPermissionsSchema.MANAGE_MEMBERS)) {
123 +                granted.add(groupResource.getId());
124 +            }
125 +        });
126 +
127 +        return granted;
128 +    }
129 +
130 +    private boolean hasPermission(String groupId, String... scopes) {
131 +        if (!root.isAdminSameRealm()) {
132 +            return false;
133 +        }
134 +
135 +        ResourceServer server = root.realmResourceServer();
136 +
137 +        if (server == null) {
138 +            return false;
139 +        }
140 +
141 +        Resource resource = groupId == null ? null : resourceStore.findByName(server, groupId);
142 +
143 +        if (resource == null) {
144 +            resource = AdminPermissionsSchema.SCHEMA.getResourceTypeResource(session, server, AdminPermissionsSchema.GROUPS_RESOURCE_TYPE);
145 +
146 +            // check if there is a permission for "all-groups". If so, proceed with the evaluation to check scopes
147 +            if (policyStore.findByResource(server, resource).isEmpty()) {
148 +                return false;
149 +            }
150 +        }
151 +
152 +        Collection<Permission> permissions = root.evaluatePermission(new ResourcePermission(resource, resource.getScopes(), server), server);
153 +
154 +        List<String> expectedScopes = Arrays.asList(scopes);
155 +
156 +        for (Permission permission : permissions) {
157 +            for (String scope : permission.getScopes()) {
158 +                if (expectedScopes.contains(scope)) {
159 +                    return true;
160 +                }
161 +            }
162 +        }
163 +
164 +        return false;
165 +    }
